mapper.select:
		 SELECT 	COUNT(*)
      	 FROM s_common_file_main
      	 WHERE 		FM_KEYNO = #{FM_KEYNO}

mapper.insert:
       	INSERT INTO s_common_file_main
		(
			   FM_KEYNO
			 , FM_REGDT
			 , FM_REGNM
			 , FM_WHERE_KEYS
       		 , FM_COMMENTS
			 , FM_ZIP_PATH
		)
		VALUES
		(
	   		   FM_SEQ.NEXTVAL
			 , SYSDATE
			 , #{FM_REGNM}
			 , #{FM_WHERE_KEYS}
      	     , #{FM_COMMENTS}
      	     , #{FM_ZIP_PATH}
		)

			SELECT FM_SEQ.CURRVAL  FROM dual

       	INSERT INTO s_common_file_sub
		(
			 FS_KEYNO
			,FS_FM_KEYNO
			,FS_FILE_SIZE
			,FS_ORINM
			,FS_CHANGENM
			,FS_EXT
			,FS_FOLDER
			,FS_M_KEYNO
			,FS_REGDT
			,FS_REGNM
			,FS_THUMBNAIL
			,FS_ALT
	        ,FS_COMMENTS
	        ,FS_ORIWIDTH
	        ,FS_ORIHEIGHT

			,FS_STORAGE
			,FS_PUBLIC_PATH
			,FS_CONVERT_CHK
		)
		VALUES
		(
   		  FS_SEQ.NEXTVAL
		 ,#{FS_FM_KEYNO}
		 ,#{FS_FILE_SIZE}
		 ,#{FS_ORINM}
	  	 ,#{FS_CHANGENM}
	     ,#{FS_EXT}
	     ,#{FS_FOLDER}
	     ,#{FS_M_KEYNO}
	     ,SYSDATE
	     ,#{FS_REGNM}
	     ,#{FS_THUMBNAIL}
	     ,#{FS_ALT}
         ,#{FS_COMMENTS}
         ,#{FS_ORIWIDTH}
         ,#{FS_ORIHEIGHT}
         ,#{FS_STORAGE}
		 ,#{FS_PUBLIC_PATH}
		 ,#{FS_CONVERT_CHK}
		)

			SELECT FS_SEQ.CURRVAL  FROM dual

mapper.update:

UPDATE s_common_file_sub
SET			FS_DOWNCNT	=	FS_DOWNCNT + 1
WHERE		FS_KEYNO 	= 	#{FS_KEYNO}

UPDATE s_common_file_main
SET FM_ZIP_PATH = #{FM_ZIP_PATH}
WHERE FM_KEYNO = #{FM_KEYNO}

mapper.select:
SELECT FM.*, (SELECT BN_TITLE FROM b_board_notice WHERE BN_FM_KEYNO = #{FM_KEYNO}) ZIP_NAME
FROM s_common_file_main FM
WHERE FM_KEYNO = #{FM_KEYNO}

mapper.update:
UPDATE s_common_file_sub
SET 	FS_FOLDER 		= #{FS_FOLDER}
	 , 	FS_PUBLIC_PATH 	= #{FS_PUBLIC_PATH}
WHERE 	FS_KEYNO = #{FS_KEYNO}

UPDATE s_common_file_sub
SET 	FS_CONVERT_CHK = #{FS_CONVERT_CHK}
		,FS_CONVERT_PATH = #{FS_CONVERT_PATH}
WHERE 	FS_KEYNO = #{FS_KEYNO}

mapper.select:
SELECT FS_KEYNO
FROM s_common_file_sub 
WHERE FS_FM_KEYNO= #{FM_KEYNO}
